import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';
import vemuLogo from '../assets/vemu-logo.jpg';

const loginStyles = `
  @keyframes fadeIn { from{opacity:0;transform:translateY(30px)} to{opacity:1;transform:translateY(0)} }
  @keyframes logoIn { from{opacity:0;transform:scale(0.6) rotate(-10deg)} to{opacity:1;transform:scale(1) rotate(0)} }
  @keyframes pulse  { 0%,100%{transform:scale(1)} 50%{transform:scale(1.04)} }
  @keyframes shimmer { 0%{background-position:200% center} 100%{background-position:-200% center} }
  @keyframes overlayIn { from{opacity:0} to{opacity:1} }
  .login-wrap    { animation: fadeIn 0.7s cubic-bezier(0.34,1.56,0.64,1) both; }
  .logo-anim     { animation: logoIn 0.6s cubic-bezier(0.34,1.56,0.64,1) 0.2s both; }
  .popup-overlay { animation: overlayIn 0.2s ease both; }

  .login-input {
    width:100%; padding:13px 16px; border-radius:12px; font-size:14px; font-weight:600;
    outline:none; box-sizing:border-box; transition:all 0.25s;
    background:#f8fafc; border:2px solid #e2e8f0; color:#0f172a;
  }
  .login-input:focus { background:white; border-color:#6366f1; box-shadow:0 0 0 4px rgba(99,102,241,0.12); }
  .login-input::placeholder { color:#94a3b8; font-weight:400; }

  .login-btn {
    width:100%; padding:14px; border-radius:12px; font-size:15px; font-weight:800;
    cursor:pointer; transition:all 0.25s; letter-spacing:0.5px; border:none;
    background: linear-gradient(135deg, #6366f1 0%, #4f46e5 50%, #7c3aed 100%);
    background-size: 200% auto; color:white;
    box-shadow: 0 4px 20px rgba(99,102,241,0.4);
  }
  .login-btn:hover:not(:disabled) {
    background-position: right center;
    transform:translateY(-2px); box-shadow:0 8px 25px rgba(99,102,241,0.5);
  }
  .login-btn:disabled { opacity:0.7; cursor:not-allowed; transform:none; }

  .tab-btn {
    flex:1; padding:12px 8px; border:none; cursor:pointer; font-size:14px; font-weight:700;
    transition:all 0.2s; background:transparent; letter-spacing:0.3px;
  }
  .tab-btn.active { background:white; color:#4f46e5; border-bottom:3px solid #4f46e5; box-shadow:0 2px 8px rgba(0,0,0,0.06); }
  .tab-btn:not(.active) { color:#94a3b8; border-bottom:3px solid transparent; }

  .feature-chip {
    display:inline-flex; align-items:center; gap:5px; padding:5px 12px;
    background:rgba(99,102,241,0.08); border:1px solid rgba(99,102,241,0.2);
    border-radius:20px; font-size:11.5px; font-weight:600; color:#4f46e5;
  }
  .popup-btn {
    padding:14px; border-radius:12px; font-weight:800; font-size:14px;
    cursor:pointer; transition:all 0.2s; width:100%;
  }
  .popup-btn:hover { transform:translateY(-1px); }
`;

export default function Login() {
  const [activeTab,     setActiveTab]     = useState('Faculty');
  const [rollNumber,    setRollNumber]    = useState('');
  const [password,      setPassword]      = useState('');
  const [showPass,      setShowPass]      = useState(false);
  const [loading,       setLoading]       = useState(false);
  const [showRolePopup, setShowRolePopup] = useState(false);
  const [showDeptPopup, setShowDeptPopup] = useState(false);
  const [hodDepts,      setHodDepts]      = useState([]);
  const [pendingCreds,  setPendingCreds]  = useState(null);

  const { login } = useAuth();
  const navigate  = useNavigate();
  const roleRoutes = { admin:'/admin', hod:'/hod', faculty:'/faculty', student:'/student' };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!rollNumber.trim() || !password.trim()) { toast.error('Please enter credentials'); return; }
    setLoading(true);
    try {
      const tabType = activeTab === 'Student' ? 'student' : 'faculty';
      const result  = await login(rollNumber.trim(), password, tabType);
      if (result.requiresRoleSelection) {
        setHodDepts(result.hodDepartments || []);
        setPendingCreds({ rollNumber: rollNumber.trim(), password, tabType });
        setShowRolePopup(true);
        return;
      }
      toast.success(`Welcome, ${result.name}!`);
      navigate(roleRoutes[result.role] || '/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally { setLoading(false); }
  };

  const handleRoleChoice = async (choice) => {
    setShowRolePopup(false);
    if (choice === 'faculty') {
      setLoading(true);
      try { const user = await login(pendingCreds.rollNumber, pendingCreds.password, pendingCreds.tabType, 'faculty'); toast.success(`Welcome, ${user.name}!`); navigate('/faculty'); }
      catch { toast.error('Login failed'); } finally { setLoading(false); }
    } else {
      if (hodDepts.length > 1) setShowDeptPopup(true);
      else await loginAsHod(hodDepts[0]?._id);
    }
  };

  const loginAsHod = async (deptId) => {
    setShowDeptPopup(false); setLoading(true);
    try { const user = await login(pendingCreds.rollNumber, pendingCreds.password, pendingCreds.tabType, 'hod', deptId); toast.success(`Welcome, ${user.name}! (HOD)`); navigate('/hod'); }
    catch { toast.error('Login failed'); } finally { setLoading(false); }
  };

  const handleTabChange = (tab) => { setActiveTab(tab); setRollNumber(''); setPassword(''); };

  const Popup = ({ children }) => (
    <div className="popup-overlay" style={{ position:'fixed',inset:0,background:'rgba(15,23,42,0.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999,backdropFilter:'blur(4px)' }}>
      <div style={{ background:'white',borderRadius:20,padding:'36px 28px',maxWidth:400,width:'90%',boxShadow:'0 25px 60px rgba(0,0,0,0.3)' }}>
        {children}
      </div>
    </div>
  );

  return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:"'Segoe UI',system-ui,sans-serif",
      background:'linear-gradient(135deg, #0f0c29 0%, #302b63 40%, #24243e 70%, #0f0c29 100%)', position:'relative', overflow:'hidden' }}>
      <style>{loginStyles}</style>

      {/* Animated background blobs */}
      <div style={{ position:'absolute',inset:0,overflow:'hidden',pointerEvents:'none' }}>
        <div style={{ position:'absolute',top:'-20%',left:'-10%',width:600,height:600,borderRadius:'50%',background:'radial-gradient(circle,rgba(99,102,241,0.25) 0%,transparent 70%)',filter:'blur(40px)' }}/>
        <div style={{ position:'absolute',bottom:'-20%',right:'-10%',width:500,height:500,borderRadius:'50%',background:'radial-gradient(circle,rgba(124,58,237,0.25) 0%,transparent 70%)',filter:'blur(40px)' }}/>
        <div style={{ position:'absolute',top:'40%',left:'50%',width:400,height:400,borderRadius:'50%',background:'radial-gradient(circle,rgba(79,70,229,0.15) 0%,transparent 70%)',filter:'blur(60px)' }}/>
        {/* Grid pattern */}
        <div style={{ position:'absolute',inset:0,backgroundImage:'linear-gradient(rgba(255,255,255,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,0.03) 1px,transparent 1px)',backgroundSize:'50px 50px' }}/>
      </div>

      {/* Popup modals */}
      {showRolePopup && (
        <Popup>
          <div style={{ textAlign:'center' }}>
            <div style={{ width:64,height:64,borderRadius:'50%',background:'linear-gradient(135deg,#6366f1,#7c3aed)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28,margin:'0 auto 16px' }}>👤</div>
            <h2 style={{ margin:'0 0 8px',fontSize:20,fontWeight:900,color:'#0f172a' }}>Choose Login Type</h2>
            <p style={{ margin:'0 0 24px',fontSize:14,color:'#64748b' }}>You have both Faculty and HOD access.</p>
            <div style={{ display:'flex',gap:12,flexDirection:'column' }}>
              <button className="popup-btn" onClick={() => handleRoleChoice('faculty')} style={{ border:'2px solid #6366f1',background:'white',color:'#4f46e5' }}>👩‍🏫 Login as Faculty</button>
              <button className="popup-btn" onClick={() => handleRoleChoice('hod')} style={{ border:'none',background:'linear-gradient(135deg,#6366f1,#7c3aed)',color:'white',boxShadow:'0 4px 15px rgba(99,102,241,0.4)' }}>🧑‍💼 Login as HOD</button>
            </div>
          </div>
        </Popup>
      )}
      {showDeptPopup && (
        <Popup>
          <div style={{ textAlign:'center' }}>
            <div style={{ width:64,height:64,borderRadius:'50%',background:'linear-gradient(135deg,#6366f1,#7c3aed)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28,margin:'0 auto 16px' }}>🏢</div>
            <h2 style={{ margin:'0 0 8px',fontSize:20,fontWeight:900,color:'#0f172a' }}>Select Department</h2>
            <p style={{ margin:'0 0 20px',fontSize:14,color:'#64748b' }}>Which department do you want to manage?</p>
            <div style={{ display:'flex',gap:10,flexDirection:'column' }}>
              {hodDepts.map(dept => (
                <button key={dept._id} className="popup-btn" onClick={() => loginAsHod(dept._id)}
                  style={{ border:'2px solid #e2e8f0',background:'white',color:'#0f172a',textAlign:'left',display:'flex',alignItems:'center',gap:10 }}
                  onMouseEnter={e=>{e.currentTarget.style.borderColor='#6366f1';e.currentTarget.style.background='#f5f3ff';}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor='#e2e8f0';e.currentTarget.style.background='white';}}>
                  <span style={{ fontSize:22 }}>🏛</span>
                  <div style={{ textAlign:'left' }}>
                    <div style={{ fontWeight:800 }}>{dept.name}</div>
                    <div style={{ fontSize:12,color:'#6366f1' }}>{dept.code}</div>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </Popup>
      )}

      {/* Main card */}
      <div className="login-wrap" style={{ width:440,maxWidth:'92vw',position:'relative',zIndex:1 }}>
        {/* Glow effect behind card */}
        <div style={{ position:'absolute',inset:-2,borderRadius:26,background:'linear-gradient(135deg,#6366f1,#7c3aed,#4f46e5)',filter:'blur(20px)',opacity:0.5,zIndex:-1 }}/>

        <div style={{ background:'rgba(255,255,255,0.97)',borderRadius:24,overflow:'hidden',boxShadow:'0 30px 80px rgba(0,0,0,0.4)' }}>

          {/* Header */}
          <div style={{ background:'linear-gradient(135deg,#4f46e5 0%,#6366f1 50%,#7c3aed 100%)',padding:'32px 28px 28px',textAlign:'center',position:'relative',overflow:'hidden' }}>
            {/* Decorative circles */}
            <div style={{ position:'absolute',top:-30,right:-30,width:120,height:120,borderRadius:'50%',background:'rgba(255,255,255,0.08)' }}/>
            <div style={{ position:'absolute',bottom:-20,left:-20,width:80,height:80,borderRadius:'50%',background:'rgba(255,255,255,0.06)' }}/>

            {/* Logo */}
            <div className="logo-anim" style={{ width:88,height:88,borderRadius:'50%',overflow:'hidden',margin:'0 auto 16px',border:'3px solid rgba(255,255,255,0.5)',boxShadow:'0 8px 32px rgba(0,0,0,0.3)',position:'relative',zIndex:1 }}>
              <img src={vemuLogo} alt="VEMU" style={{ width:'100%',height:'100%',objectFit:'cover' }} />
            </div>
            <h1 style={{ fontSize:20,fontWeight:900,margin:'0 0 6px',color:'white',letterSpacing:0.3,position:'relative',zIndex:1 }}>
              VEMU Institute of Technology
            </h1>
            <p style={{ fontSize:11,margin:'0 0 16px',color:'rgba(255,255,255,0.75)',letterSpacing:3,textTransform:'uppercase',fontWeight:700,position:'relative',zIndex:1 }}>
              Student Mid Marks System
            </p>
            <div style={{ display:'flex',gap:8,justifyContent:'center',flexWrap:'wrap',position:'relative',zIndex:1 }}>
              <span className="feature-chip" style={{ background:'rgba(255,255,255,0.15)',borderColor:'rgba(255,255,255,0.25)',color:'rgba(255,255,255,0.9)' }}>📊 Mid Marks</span>
              <span className="feature-chip" style={{ background:'rgba(255,255,255,0.15)',borderColor:'rgba(255,255,255,0.25)',color:'rgba(255,255,255,0.9)' }}>📋 Reports</span>
              <span className="feature-chip" style={{ background:'rgba(255,255,255,0.15)',borderColor:'rgba(255,255,255,0.25)',color:'rgba(255,255,255,0.9)' }}>✅ Approvals</span>
            </div>
          </div>

          {/* Tabs */}
          <div style={{ display:'flex',borderBottom:'2px solid #f1f5f9',background:'#fafbff' }}>
            {['Faculty','Student'].map(tab => (
              <button key={tab} className={`tab-btn ${activeTab===tab?'active':''}`} onClick={() => handleTabChange(tab)}>
                {tab === 'Faculty' ? '👩‍🏫' : '👨‍🎓'} {tab}
              </button>
            ))}
          </div>

          {/* Body */}
          <div style={{ padding:'24px 28px 28px' }}>
            {/* Hint */}
            <div style={{ background:'linear-gradient(135deg,#f5f3ff,#ede9fe)',border:'1.5px solid #c4b5fd',borderRadius:10,padding:'10px 14px',fontSize:12.5,marginBottom:20,color:'#4c1d95',fontWeight:600,textAlign:'center' }}>
              {activeTab==='Student' ? '🎓 Students — enter your Roll Number' : '🔐 Faculty, HOD & Admin — enter your Employee ID'}
            </div>

            <form onSubmit={handleSubmit}>
              <div style={{ marginBottom:16 }}>
                <label style={{ display:'block',fontSize:13,fontWeight:700,color:'#374151',marginBottom:7 }}>
                  {activeTab==='Student' ? 'Roll Number' : 'Employee / Roll Number'}
                </label>
                <input className="login-input" type="text"
                  placeholder={activeTab==='Student' ? 'e.g. 22CS1A0501' : 'e.g. FAC001 / ADMIN001'}
                  value={rollNumber} onChange={e=>setRollNumber(e.target.value)}
                  autoFocus autoComplete="username" />
              </div>

              <div style={{ marginBottom:24 }}>
                <label style={{ display:'block',fontSize:13,fontWeight:700,color:'#374151',marginBottom:7 }}>Password</label>
                <div style={{ position:'relative' }}>
                  <input className="login-input" type={showPass?'text':'password'}
                    placeholder="Enter your password"
                    value={password} onChange={e=>setPassword(e.target.value)}
                    autoComplete="current-password" style={{ paddingRight:48 }} />
                  <button type="button" onClick={()=>setShowPass(v=>!v)} style={{
                    position:'absolute',right:14,top:'50%',transform:'translateY(-50%)',
                    background:'none',border:'none',cursor:'pointer',fontSize:18,color:'#94a3b8',padding:4,lineHeight:1
                  }}>
                    {showPass ? '🙈' : '👁'}
                  </button>
                </div>
              </div>

              <button type="submit" className="login-btn" disabled={loading}>
                {loading ? '⏳ Signing In...' : '🚀 Sign In'}
              </button>
            </form>

            <div style={{ textAlign:'center',marginTop:18,padding:'12px 0',borderTop:'1px solid #f1f5f9',fontSize:12,color:'#94a3b8' }}>
              Default password: <strong style={{ color:'#4f46e5' }}>{activeTab==='Student'?'Your Roll Number':'Your Employee ID'}</strong>
            </div>
          </div>

          {/* Footer */}
          <div style={{ textAlign:'center',padding:'12px 16px',background:'#f8fafc',borderTop:'1px solid #f1f5f9',fontSize:11.5,color:'#94a3b8',fontWeight:600 }}>
            © 2024 VEMU Institute of Technology, P.Kothakota
          </div>
        </div>
      </div>
    </div>
  );
}
